window.docContents[79].resolve({"/Aula-2___-L___gica-de-Predicados-e-Conjuntos/#aula-2":{"contents":"Esta aula estende a lógica proposicional com quantificadores e introduz conjuntos, seguindo os capítulos 2 e 3 de How To Prove It with Lean (HTPIwL). Ela apresenta as regras de prova dos quantificadores universal e existencial, as leis que os relacionam sob negação e conjuntos como predicados em Lean.\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n","context":"Verificação Formal de Software","header":"2. Aula 2: Lógica de Predicados e Conjuntos","id":"/Aula-2___-L___gica-de-Predicados-e-Conjuntos/#aula-2"}});